  1вҶ’use anyhow::{Context, Result};
  2вҶ’use chrono::{DateTime, Utc};
  3вҶ’use serde::{Deserialize, Serialize};
  4вҶ’use std::fs;
  5вҶ’use std::io::Write;
  6вҶ’use tracing::warn;
  7вҶ’
  8вҶ’#[derive(Debug, Clone, Serialize, Deserialize)]
  9вҶ’pub struct StateEntry {
 10вҶ’    pub phase: String,
 11вҶ’    /// Sub-phase number if this is a sub-phase entry (e.g., "05.1")
 12вҶ’    #[serde(default, skip_serializing_if = "Option::is_none")]
 13вҶ’    pub sub_phase: Option<String>,
 14вҶ’    pub iteration: u32,
 15вҶ’    pub status: String,
 16вҶ’    pub timestamp: DateTime<Utc>,
 17вҶ’}
 18вҶ’
 19вҶ’impl StateEntry {
 20вҶ’    /// Check if this is a sub-phase entry.
 21вҶ’    pub fn is_sub_phase(&self) -> bool {
 22вҶ’        self.sub_phase.is_some()
 23вҶ’    }
 24вҶ’
 25вҶ’    /// Get the full phase/sub-phase identifier.
 26вҶ’    pub fn full_phase_id(&self) -> String {
 27вҶ’        self.sub_phase.clone().unwrap_or_else(|| self.phase.clone())
 28вҶ’    }
 29вҶ’
 30вҶ’    /// Get the parent phase number for sub-phase entries.
 31вҶ’    pub fn parent_phase(&self) -> &str {
 32вҶ’        &self.phase
 33вҶ’    }
 34вҶ’}
 35вҶ’
 36вҶ’pub struct StateManager {
 37вҶ’    state_file: std::path::PathBuf,
 38вҶ’}
 39вҶ’
 40вҶ’impl StateManager {
 41вҶ’    pub fn new(state_file: std::path::PathBuf) -> Self {
 42вҶ’        Self { state_file }
 43вҶ’    }
 44вҶ’
 45вҶ’    /// Save a phase state entry (legacy format, backward compatible).
 46вҶ’    pub fn save(&self, phase: &str, iteration: u32, status: &str) -> Result<()> {
 47вҶ’        let entry = format!(
 48вҶ’            "{}|{}|{}|{}\n",
 49вҶ’            phase,
 50вҶ’            iteration,
 51вҶ’            status,
 52вҶ’            Utc::now().to_rfc3339()
 53вҶ’        );
 54вҶ’
 55вҶ’        fs::OpenOptions::new()
 56вҶ’            .create(true)
 57вҶ’            .append(true)
 58вҶ’            .open(&self.state_file)
 59вҶ’            .context("Failed to open state file")?
 60вҶ’            .write_all(entry.as_bytes())
 61вҶ’            .context("Failed to write state entry")?;
 62вҶ’
 63вҶ’        Ok(())
 64вҶ’    }
 65вҶ’
 66вҶ’    /// Save a sub-phase state entry with parent phase reference.
 67вҶ’    /// Format: phase|sub_phase|iteration|status|timestamp
 68вҶ’    pub fn save_sub_phase(
 69вҶ’        &self,
 70вҶ’        parent_phase: &str,
 71вҶ’        sub_phase: &str,
 72вҶ’        iteration: u32,
 73вҶ’        status: &str,
 74вҶ’    ) -> Result<()> {
 75вҶ’        let entry = format!(
 76вҶ’            "{}|{}|{}|{}|{}\n",
 77вҶ’            parent_phase,
 78вҶ’            sub_phase,
 79вҶ’            iteration,
 80вҶ’            status,
 81вҶ’            Utc::now().to_rfc3339()
 82вҶ’        );
 83вҶ’
 84вҶ’        fs::OpenOptions::new()
 85вҶ’            .create(true)
 86вҶ’            .append(true)
 87вҶ’            .open(&self.state_file)
 88вҶ’            .context("Failed to open state file")?
 89вҶ’            .write_all(entry.as_bytes())
 90вҶ’            .context("Failed to write sub-phase state entry")?;
 91вҶ’
 92вҶ’        Ok(())
 93вҶ’    }
 94вҶ’
 95вҶ’    /// Get the last completed top-level phase (not sub-phases).
 96вҶ’    pub fn get_last_completed_phase(&self) -> Option<String> {
 97вҶ’        if !self.state_file.exists() {
 98вҶ’            return None;
 99вҶ’        }
100вҶ’
101вҶ’        let content = fs::read_to_string(&self.state_file).ok()?;
102вҶ’
103вҶ’        content
104вҶ’            .lines()
105вҶ’            .rfind(|line| {
106вҶ’                let parts: Vec<&str> = line.split('|').collect();
107вҶ’                // Old format has 4 parts, new sub-phase format has 5 parts
108вҶ’                // Only consider old format (top-level phases) for this query
109вҶ’                parts.len() == 4 && line.contains("|completed|")
110вҶ’            })
111вҶ’            .and_then(|line| line.split('|').next())
112вҶ’            .map(|s| s.to_string())
113вҶ’    }
114вҶ’
115вҶ’    /// Get the last completed phase or sub-phase.
116вҶ’    pub fn get_last_completed_any(&self) -> Option<String> {
117вҶ’        if !self.state_file.exists() {
118вҶ’            return None;
119вҶ’        }
120вҶ’
121вҶ’        let content = fs::read_to_string(&self.state_file).ok()?;
122вҶ’
123вҶ’        content
124вҶ’            .lines()
125вҶ’            .rfind(|line| line.contains("|completed|"))
126вҶ’            .and_then(|line| {
127вҶ’                let parts: Vec<&str> = line.split('|').collect();
128вҶ’                if parts.len() == 5 {
129вҶ’                    // Sub-phase format: phase|sub_phase|iteration|status|timestamp
130вҶ’                    Some(parts[1].to_string()) // Return sub-phase number
131вҶ’                } else if parts.len() >= 4 {
132вҶ’                    // Old format: phase|iteration|status|timestamp
133вҶ’                    Some(parts[0].to_string())
134вҶ’                } else {
135вҶ’                    None
136вҶ’                }
137вҶ’            })
138вҶ’    }
139вҶ’
140вҶ’    /// Get all state entries including sub-phase entries.
141вҶ’    ///
142вҶ’    /// Lines that cannot be fully parsed (e.g. corrupt or partial writes) are
143вҶ’    /// silently skipped with a warning rather than being returned as bogus
144вҶ’    /// entries with iteration == 0.
145вҶ’    pub fn get_entries(&self) -> Result<Vec<StateEntry>> {
146вҶ’        if !self.state_file.exists() {
147вҶ’            return Ok(Vec::new());
148вҶ’        }
149вҶ’
150вҶ’        let content = fs::read_to_string(&self.state_file).context("Failed to read state file")?;
151вҶ’
152вҶ’        let entries: Vec<StateEntry> = content
153вҶ’            .lines()
154вҶ’            .filter_map(|line| {
155вҶ’                let parts: Vec<&str> = line.split('|').collect();
156вҶ’                if parts.len() == 5 {
157вҶ’                    // New sub-phase format: phase|sub_phase|iteration|status|timestamp
158вҶ’                    let iteration = match parts[2].parse::<u32>() {
159вҶ’                        Ok(n) => n,
160вҶ’                        Err(_) => {
161вҶ’                            warn!(
162вҶ’                                "state: skipping malformed sub-phase line (bad iteration): {line}"
163вҶ’                            );
164вҶ’                            return None;
165вҶ’                        }
166вҶ’                    };
167вҶ’                    Some(StateEntry {
168вҶ’                        phase: parts[0].to_string(),
169вҶ’                        sub_phase: Some(parts[1].to_string()),
170вҶ’                        iteration,
171вҶ’                        status: parts[3].to_string(),
172вҶ’                        timestamp: DateTime::parse_from_rfc3339(parts[4])
173вҶ’                            .ok()?
174вҶ’                            .with_timezone(&Utc),
175вҶ’                    })
176вҶ’                } else if parts.len() >= 4 {
177вҶ’                    // Old format: phase|iteration|status|timestamp
178вҶ’                    let iteration = match parts[1].parse::<u32>() {
179вҶ’                        Ok(n) => n,
180вҶ’                        Err(_) => {
181вҶ’                            warn!("state: skipping malformed entry line (bad iteration): {line}");
182вҶ’                            return None;
183вҶ’                        }
184вҶ’                    };
185вҶ’                    Some(StateEntry {
186вҶ’                        phase: parts[0].to_string(),
187вҶ’                        sub_phase: None,
188вҶ’                        iteration,
189вҶ’                        status: parts[2].to_string(),
190вҶ’                        timestamp: DateTime::parse_from_rfc3339(parts[3])
191вҶ’                            .ok()?
192вҶ’                            .with_timezone(&Utc),
193вҶ’                    })
194вҶ’                } else {
195вҶ’                    None
196вҶ’                }
197вҶ’            })
198вҶ’            .collect();
199вҶ’
200вҶ’        Ok(entries)
201вҶ’    }
202вҶ’
203вҶ’    /// Get entries for a specific phase including its sub-phases.
204вҶ’    pub fn get_phase_entries(&self, phase: &str) -> Result<Vec<StateEntry>> {
205вҶ’        let entries = self.get_entries()?;
206вҶ’        Ok(entries.into_iter().filter(|e| e.phase == phase).collect())
207вҶ’    }
208вҶ’
209вҶ’    /// Get entries for a specific sub-phase.
210вҶ’    pub fn get_sub_phase_entries(&self, sub_phase: &str) -> Result<Vec<StateEntry>> {
211вҶ’        let entries = self.get_entries()?;
212вҶ’        Ok(entries
213вҶ’            .into_iter()
214вҶ’            .filter(|e| e.sub_phase.as_deref() == Some(sub_phase))
215вҶ’            .collect())
216вҶ’    }
217вҶ’
218вҶ’    /// Check if a phase has any sub-phase entries.
219вҶ’    pub fn has_sub_phase_entries(&self, phase: &str) -> Result<bool> {
220вҶ’        let entries = self.get_phase_entries(phase)?;
221вҶ’        Ok(entries.iter().any(|e| e.is_sub_phase()))
222вҶ’    }
223вҶ’
224вҶ’    /// Get all completed sub-phases for a parent phase.
225вҶ’    pub fn get_completed_sub_phases(&self, parent_phase: &str) -> Result<Vec<String>> {
226вҶ’        let entries = self.get_phase_entries(parent_phase)?;
227вҶ’        Ok(entries
228вҶ’            .into_iter()
229вҶ’            .filter(|e| e.is_sub_phase() && e.status == "completed")
230вҶ’            .filter_map(|e| e.sub_phase)
231вҶ’            .collect())
232вҶ’    }
233вҶ’
234вҶ’    /// Check if all sub-phases of a parent are complete.
235вҶ’    pub fn all_sub_phases_complete(
236вҶ’        &self,
237вҶ’        parent_phase: &str,
238вҶ’        expected_count: usize,
239вҶ’    ) -> Result<bool> {
240вҶ’        let completed = self.get_completed_sub_phases(parent_phase)?;
241вҶ’        Ok(completed.len() >= expected_count)
242вҶ’    }
243вҶ’
244вҶ’    pub fn reset(&self) -> Result<()> {
245вҶ’        if self.state_file.exists() {
246вҶ’            fs::remove_file(&self.state_file).context("Failed to remove state file")?;
247вҶ’        }
248вҶ’        Ok(())
249вҶ’    }
250вҶ’}
