  1вҶ’//! DAG scheduler for computing execution order and managing phase states.
  2вҶ’//!
  3вҶ’//! The scheduler computes execution waves - groups of phases that can run in parallel
  4вҶ’//! because their dependencies are satisfied.
  5вҶ’
  6вҶ’use crate::dag::builder::{DagBuilder, PhaseGraph, PhaseIndex};
  7вҶ’use crate::phase::Phase;
  8вҶ’use anyhow::{Context, Result};
  9вҶ’use serde::{Deserialize, Serialize};
 10вҶ’use std::collections::HashSet;
