170вҶ’/// Status of a phase in the DAG.
171вҶ’#[derive(Debug, Clone, PartialEq, Serialize, Deserialize, Default)]
172вҶ’#[serde(rename_all = "snake_case")]
173вҶ’pub enum PhaseStatus {
174вҶ’    /// Phase is waiting to run
175вҶ’    #[default]
176вҶ’    Pending,
177вҶ’    /// Phase is waiting for dependencies
178вҶ’    Blocked { waiting_on: Vec<String> },
179вҶ’    /// Phase is ready to run (dependencies satisfied)
180вҶ’    Ready,
181вҶ’    /// Phase is currently running
182вҶ’    Running { started_at_ms: u64 },
183вҶ’    /// Phase completed successfully
184вҶ’    Completed { iterations: u32 },
185вҶ’    /// Phase failed
186вҶ’    Failed { error: String },
187вҶ’    /// Phase was skipped (due to dependency failure)
188вҶ’    Skipped,
189вҶ’}
190вҶ’
191вҶ’impl PhaseStatus {
192вҶ’    /// Check if the phase is in a terminal state.
193вҶ’    pub fn is_terminal(&self) -> bool {
194вҶ’        matches!(
195вҶ’            self,
196вҶ’            Self::Completed { .. } | Self::Failed { .. } | Self::Skipped
197вҶ’        )
198вҶ’    }
199вҶ’
200вҶ’    /// Check if the phase completed successfully.
201вҶ’    pub fn is_success(&self) -> bool {
202вҶ’        matches!(self, Self::Completed { .. })
203вҶ’    }
204вҶ’
205вҶ’    /// Check if the phase is ready to run.
206вҶ’    pub fn is_ready(&self) -> bool {
207вҶ’        matches!(self, Self::Ready)
208вҶ’    }
209вҶ’
210вҶ’    /// Check if the phase is running.
211вҶ’    pub fn is_running(&self) -> bool {
212вҶ’        matches!(self, Self::Running { .. })
213вҶ’    }
214вҶ’}
