246вҶ’/// The main DAG scheduler.
247вҶ’#[derive(Debug)]
248вҶ’pub struct DagScheduler {
249вҶ’    /// The underlying phase graph
250вҶ’    graph: PhaseGraph,
251вҶ’    /// Phase nodes with status
252вҶ’    nodes: Vec<PhaseNode>,
253вҶ’    /// Configuration
254вҶ’    config: DagConfig,
255вҶ’    /// Set of completed phase indices
256вҶ’    completed: HashSet<PhaseIndex>,
257вҶ’    /// Set of failed phase indices
258вҶ’    failed: HashSet<PhaseIndex>,
259вҶ’}
260вҶ’
261вҶ’impl DagScheduler {
262вҶ’    /// Create a DAG scheduler from a list of phases.
263вҶ’    pub fn from_phases(phases: &[Phase], config: DagConfig) -> Result<Self> {
264вҶ’        let graph = DagBuilder::new(phases.to_vec())
265вҶ’            .build()
266вҶ’            .context("Failed to build phase dependency graph")?;
267вҶ’
268вҶ’        let nodes: Vec<PhaseNode> = graph
269вҶ’            .phases()
270вҶ’            .iter()
271вҶ’            .enumerate()
272вҶ’            .map(|(i, p)| PhaseNode::new(p.clone(), i))
273вҶ’            .collect();
274вҶ’
275вҶ’        Ok(Self {
276вҶ’            graph,
277вҶ’            nodes,
278вҶ’            config,
279вҶ’            completed: HashSet::new(),
280вҶ’            failed: HashSet::new(),
281вҶ’        })
282вҶ’    }
283вҶ’
284вҶ’    /// Get the number of phases in the DAG.
285вҶ’    pub fn phase_count(&self) -> usize {
286вҶ’        self.graph.len()
287вҶ’    }
288вҶ’
289вҶ’    /// Get a phase node by its number.
290вҶ’    pub fn get_node(&self, number: &str) -> Option<&PhaseNode> {
291вҶ’        self.graph.get_index(number).and_then(|i| self.nodes.get(i))
292вҶ’    }
293вҶ’
294вҶ’    /// Get a mutable reference to a phase node.
295вҶ’    pub fn get_node_mut(&mut self, number: &str) -> Option<&mut PhaseNode> {
296вҶ’        let index = self.graph.get_index(number)?;
297вҶ’        self.nodes.get_mut(index)
298вҶ’    }
299вҶ’
300вҶ’    /// Get all phase nodes.
301вҶ’    pub fn nodes(&self) -> &[PhaseNode] {
302вҶ’        &self.nodes
303вҶ’    }
304вҶ’
305вҶ’    /// Get the configuration.
306вҶ’    pub fn config(&self) -> &DagConfig {
307вҶ’        &self.config
308вҶ’    }
309вҶ’
310вҶ’    /// Compute execution waves - groups of phases that can run in parallel.
311вҶ’    ///
312вҶ’    /// Returns a list of waves, where each wave is a list of phase numbers
313вҶ’    /// that can be executed in parallel once all previous waves complete.
314вҶ’    pub fn compute_waves(&self) -> Vec<Vec<String>> {
315вҶ’        let mut waves = Vec::new();
316вҶ’        let mut completed: HashSet<PhaseIndex> = HashSet::new();
317вҶ’
318вҶ’        loop {
319вҶ’            // Find all phases whose dependencies are satisfied and not yet completed
320вҶ’            let ready: Vec<String> = self
321вҶ’                .graph
322вҶ’                .phases()
323вҶ’                .iter()
324вҶ’                .enumerate()
325вҶ’                .filter_map(|(i, phase)| {
326вҶ’                    if completed.contains(&i) {
327вҶ’                        return None;
328вҶ’                    }
329вҶ’                    if self.graph.dependencies_satisfied(i, &completed) {
330вҶ’                        Some(phase.number.clone())
331вҶ’                    } else {
332вҶ’                        None
333вҶ’                    }
334вҶ’                })
335вҶ’                .collect();
336вҶ’
337вҶ’            if ready.is_empty() {
338вҶ’                break;
339вҶ’            }
340вҶ’
341вҶ’            // Mark these phases as "completed" for the next iteration
342вҶ’            for number in &ready {
343вҶ’                if let Some(idx) = self.graph.get_index(number) {
344вҶ’                    completed.insert(idx);
345вҶ’                }
346вҶ’            }
347вҶ’
348вҶ’            waves.push(ready);
349вҶ’        }
350вҶ’
351вҶ’        waves
352вҶ’    }
353вҶ’
354вҶ’    /// Get phases that are ready to run (dependencies satisfied, not started).
355вҶ’    pub fn get_ready_phases(&self) -> Vec<&PhaseNode> {
356вҶ’        self.nodes
357вҶ’            .iter()
358вҶ’            .filter(|node| {
359вҶ’                if !matches!(node.status, PhaseStatus::Pending) {
360вҶ’                    return false;
361вҶ’                }
362вҶ’                self.graph
363вҶ’                    .dependencies_satisfied(node.index, &self.completed)
364вҶ’            })
365вҶ’            .collect()
366вҶ’    }
367вҶ’
368вҶ’    /// Mark a phase as running.
369вҶ’    pub fn mark_running(&mut self, number: &str) {
370вҶ’        if let Some(node) = self.get_node_mut(number) {
371вҶ’            node.status = PhaseStatus::Running {
372вҶ’                started_at_ms: std::time::SystemTime::now()
373вҶ’                    .duration_since(std::time::UNIX_EPOCH)
374вҶ’                    .unwrap_or_default()
375вҶ’                    .as_millis() as u64,
376вҶ’            };
377вҶ’        }
378вҶ’    }
379вҶ’
380вҶ’    /// Mark a phase as completed.
381вҶ’    pub fn mark_completed(&mut self, number: &str, iterations: u32) {
382вҶ’        if let Some(idx) = self.graph.get_index(number) {
383вҶ’            if let Some(node) = self.nodes.get_mut(idx) {
384вҶ’                node.status = PhaseStatus::Completed { iterations };
385вҶ’            }
386вҶ’            self.completed.insert(idx);
387вҶ’        }
388вҶ’    }
389вҶ’
390вҶ’    /// Mark a phase as failed.
391вҶ’    pub fn mark_failed(&mut self, number: &str, error: &str) {
392вҶ’        if let Some(idx) = self.graph.get_index(number) {
393вҶ’            if let Some(node) = self.nodes.get_mut(idx) {
394вҶ’                node.status = PhaseStatus::Failed {
395вҶ’                    error: error.to_string(),
396вҶ’                };
397вҶ’            }
398вҶ’            self.failed.insert(idx);
399вҶ’
400вҶ’            // If fail_fast, skip all dependent phases
401вҶ’            if self.config.fail_fast {
402вҶ’                self.skip_dependents(idx);
403вҶ’            }
404вҶ’        }
405вҶ’    }
406вҶ’
407вҶ’    /// Mark a phase as skipped.
408вҶ’    pub fn mark_skipped(&mut self, number: &str) {
409вҶ’        if let Some(idx) = self.graph.get_index(number) {
410вҶ’            if let Some(node) = self.nodes.get_mut(idx) {
411вҶ’                node.status = PhaseStatus::Skipped;
412вҶ’            }
413вҶ’            self.failed.insert(idx); // Treat skipped as failed for dependency purposes
414вҶ’        }
415вҶ’    }
416вҶ’
417вҶ’    /// Skip all phases that depend on a failed phase.
418вҶ’    fn skip_dependents(&mut self, failed_idx: PhaseIndex) {
419вҶ’        let dependents: Vec<PhaseIndex> = self.graph.dependents(failed_idx).to_vec();
420вҶ’        for dep_idx in dependents {
421вҶ’            if let Some(node) = self.nodes.get_mut(dep_idx)
422вҶ’                && !node.status.is_terminal()
423вҶ’            {
424вҶ’                node.status = PhaseStatus::Skipped;
425вҶ’                self.failed.insert(dep_idx);
426вҶ’                // Recursively skip dependents
427вҶ’                self.skip_dependents(dep_idx);
428вҶ’            }
429вҶ’        }
430вҶ’    }
431вҶ’
432вҶ’    /// Check if all phases are complete (success or failure).
433вҶ’    pub fn all_complete(&self) -> bool {
434вҶ’        self.nodes.iter().all(|n| n.status.is_terminal())
435вҶ’    }
436вҶ’
437вҶ’    /// Check if all phases completed successfully.
438вҶ’    pub fn all_success(&self) -> bool {
439вҶ’        self.nodes.iter().all(|n| n.status.is_success())
440вҶ’    }
441вҶ’
442вҶ’    /// Get the number of completed phases.
443вҶ’    pub fn completed_count(&self) -> usize {
444вҶ’        self.completed.len()
445вҶ’    }
446вҶ’
447вҶ’    /// Get the number of failed phases.
448вҶ’    pub fn failed_count(&self) -> usize {
449вҶ’        self.failed.len()
450вҶ’    }
451вҶ’
452вҶ’    /// Get completion percentage.
453вҶ’    pub fn completion_percentage(&self) -> f64 {
454вҶ’        if self.nodes.is_empty() {
455вҶ’            return 100.0;
456вҶ’        }
457вҶ’        let terminal = self.nodes.iter().filter(|n| n.status.is_terminal()).count();
458вҶ’        (terminal as f64 / self.nodes.len() as f64) * 100.0
459вҶ’    }
460вҶ’}
