487вҶ’        let waves = scheduler.compute_waves();
488вҶ’
489вҶ’        assert_eq!(waves.len(), 3);
490вҶ’        assert_eq!(waves[0], vec!["01"]);
491вҶ’        assert_eq!(waves[1], vec!["02"]);
492вҶ’        assert_eq!(waves[2], vec!["03"]);
