 54вҶ’
 55вҶ’```
 56вҶ’match &exp_result.outcome {
 57вҶ’    ExperimentOutcome::Keep => {
 58вҶ’        let sha = git.commit(&format!("experiment: {}", exp_result.description))?;
 59вҶ’        results.append(ResultRow { status: ExperimentStatus::Keep, .. })?;
 60вҶ’        baseline_score = exp_result.score;
 61вҶ’        consecutive_failures = 0;
 62вҶ’    }
 63вҶ’    ExperimentOutcome::Discard => {
