 56вҶ’/// Serve embedded static files or fall back to index.html for SPA routing.
 57вҶ’async fn static_handler(req: Request<Body>) -> impl IntoResponse {
 58вҶ’    let path = req.uri().path().trim_start_matches('/');
 59вҶ’
 60вҶ’    // Try to serve the exact file
 61вҶ’    if !path.is_empty()
 62вҶ’        && let Some(content) = Assets::get(path)
 63вҶ’    {
 64вҶ’        let mime = mime_guess::from_path(path).first_or_octet_stream();
 65вҶ’        match Response::builder()
 66вҶ’            .header(header::CONTENT_TYPE, mime.as_ref())
 67вҶ’            .body(Body::from(content.data.to_vec()))
 68вҶ’        {
 69вҶ’            Ok(resp) => return resp.into_response(),
 70вҶ’            Err(_) => return StatusCode::INTERNAL_SERVER_ERROR.into_response(),
 71вҶ’        }
 72вҶ’    }
 73вҶ’
 74вҶ’    // Fall back to index.html for SPA client-side routing
 75вҶ’    match Assets::get("index.html") {
 76вҶ’        Some(content) => Html(String::from_utf8_lossy(&content.data).to_string()).into_response(),
 77вҶ’        None => (
 78вҶ’            StatusCode::NOT_FOUND,
 79вҶ’            "Frontend not found. Run 'npm run build' in ui/ directory.",
 80вҶ’        )
 81вҶ’            .into_response(),
 82вҶ’    }
 83вҶ’}
