102вҶ’    /// Add git change summary from the prior iteration.
103вҶ’    pub fn with_git_changes(mut self, changes: &FileChangeSummary) -> Self {
104вҶ’        if changes.is_empty() {
105вҶ’            return self;
106вҶ’        }
107вҶ’        let mut lines = vec![format!(
108вҶ’            "Files changed: {} added, {} modified, {} deleted (+{}/-{})",
109вҶ’            changes.files_added.len(),
110вҶ’            changes.files_modified.len(),
111вҶ’            changes.files_deleted.len(),
112вҶ’            changes.total_lines_added,
113вҶ’            changes.total_lines_removed,
114вҶ’        )];
115вҶ’        // Show up to 10 modified files
116вҶ’        for path in changes.files_modified.iter().take(10) {
117вҶ’            lines.push(format!("  M {}", path.display()));
118вҶ’        }
119вҶ’        for path in changes.files_added.iter().take(5) {
120вҶ’            lines.push(format!("  A {}", path.display()));
121вҶ’        }
122вҶ’        self.parts.push(lines.join("\n"));
123вҶ’        self
124вҶ’    }
125вҶ’
126вҶ’    /// Add signals from the prior iteration (progress %, blockers).
127вҶ’    /// Pivots are intentionally excluded here вҖ” use `with_pivot()` instead,
128вҶ’    /// which renders them as a prominent `## STRATEGY CHANGE` directive.
129вҶ’    pub fn with_signals(mut self, signals: &IterationSignals) -> Self {
130вҶ’        if !signals.has_signals() {
131вҶ’            return self;
132вҶ’        }
133вҶ’        let mut lines = Vec::new();
134вҶ’        if let Some(pct) = signals.latest_progress() {
135вҶ’            lines.push(format!("Progress: {}%", pct));
136вҶ’        }
137вҶ’        for blocker in &signals.blockers {
138вҶ’            if !blocker.acknowledged {
139вҶ’                lines.push(format!("Blocker: {}", blocker.description));
140вҶ’            }
141вҶ’        }
142вҶ’        if !lines.is_empty() {
143вҶ’            self.parts.push(lines.join("\n"));
144вҶ’        }
145вҶ’        self
146вҶ’    }
147вҶ’
148вҶ’    /// Inject a pivot signal as a prominent strategy-change directive.
149вҶ’    ///
150вҶ’    /// When Claude emits `<pivot>`, the new approach must override the prior
151вҶ’    /// strategy. Rendered as a `## STRATEGY CHANGE` block so it appears as an
152вҶ’    /// instruction rather than an informational note.
153вҶ’    pub fn with_pivot(mut self, pivot_text: &str) -> Self {
154вҶ’        self.parts.push(format!(
155вҶ’            "## STRATEGY CHANGE\nYou previously signalled a strategy change:\n\
156вҶ’             \"{}\"\nYou MUST follow this new approach in this iteration. \
157вҶ’             Do not repeat the prior approach.",
158вҶ’            pivot_text
159вҶ’        ));
160вҶ’        self
161вҶ’    }
