163вҶ’    /// Build the feedback string. Returns None if no content was added.
164вҶ’    ///
165вҶ’    /// ## Why feedback is injected as system prompt context
166вҶ’    ///
167вҶ’    /// Claude is invoked as a subprocess; the only ergonomic channel for
168вҶ’    /// structured per-iteration context is `--append-system-prompt`. Injecting
169вҶ’    /// here means the feedback arrives before the user-turn prompt, giving
170вҶ’    /// Claude a reliable "briefing" section it can reference without modifying
171вҶ’    /// the task prompt itself.
172вҶ’    ///
173вҶ’    /// ## Why the 4 000-character limit exists
174вҶ’    ///
175вҶ’    /// The feedback block is appended to the system prompt on *every* iteration.
176вҶ’    /// Without a cap, a phase with many file changes or a verbose blocker
177вҶ’    /// description could double the size of the system prompt, consuming
178вҶ’    /// context window tokens that Claude needs for actual work. 4 000 chars
179вҶ’    /// is roughly 1 000 tokens вҖ” large enough for meaningful signal, small
180вҶ’    /// enough not to crowd out the spec and task sections.
181вҶ’    ///
182вҶ’    /// ## What is prioritised when truncating
183вҶ’    ///
184вҶ’    /// Parts are joined in the order they were added: iteration status first,
185вҶ’    /// then git changes, then signals (progress %, blockers), and finally any
186вҶ’    /// pivot directive. Truncation cuts the trailing characters of the
187вҶ’    /// concatenated string, so higher-priority parts (status, git summary)
188вҶ’    /// survive intact while verbose tails (e.g., long file lists) are trimmed.
189вҶ’    pub fn build(self) -> Option<String> {
190вҶ’        if self.parts.is_empty() {
191вҶ’            return None;
192вҶ’        }
193вҶ’        let mut result = String::from("## ITERATION FEEDBACK\n");
194вҶ’        result.push_str(&self.parts.join("\n\n"));
195вҶ’
196вҶ’        // Truncate to 4000 chars max to prevent doubling the system prompt
197вҶ’        // size. The trailing "..." signals to Claude that output was clipped.
198вҶ’        if result.len() > 4000 {
199вҶ’            result.truncate(3997);
200вҶ’            result.push_str("...");
201вҶ’        }
202вҶ’        Some(result)
203вҶ’    }
204вҶ’}
