206вҶ’/// Extract token usage from a parsed Claude CLI result event.
207вҶ’/// Returns `None` if the value is not a `result`-type event or lacks
208вҶ’/// the expected `usage.input_tokens`/`usage.output_tokens` fields.
209вҶ’/// Note: token counts are capped at u32::MAX.
210вҶ’fn extract_token_usage(parsed: &serde_json::Value) -> Option<TokenUsage> {
211вҶ’    if parsed.get("type")?.as_str()? == "result" {
212вҶ’        let usage = parsed.get("usage")?;
213вҶ’        Some(TokenUsage {
214вҶ’            input_tokens: usage
215вҶ’                .get("input_tokens")?
216вҶ’                .as_u64()?
217вҶ’                .try_into()
218вҶ’                .unwrap_or(u32::MAX),
219вҶ’            output_tokens: usage
220вҶ’                .get("output_tokens")?
221вҶ’                .as_u64()?
222вҶ’                .try_into()
223вҶ’                .unwrap_or(u32::MAX),
224вҶ’        })
225вҶ’    } else {
226вҶ’        None
227вҶ’    }
228вҶ’}
