230вҶ’fn aggregate_council_token_usage(council_result: &CouncilPhaseResult) -> Option<TokenUsage> {
231вҶ’    let mut input_tokens = 0u64;
232вҶ’    let mut output_tokens = 0u64;
233вҶ’    let mut saw_usage = false;
234вҶ’
235вҶ’    for usage in council_result
236вҶ’        .worker_results
237вҶ’        .iter()
238вҶ’        .filter_map(|worker| worker.token_usage.as_ref())
239вҶ’    {
240вҶ’        saw_usage = true;
241вҶ’        input_tokens += u64::from(usage.input_tokens);
242вҶ’        output_tokens += u64::from(usage.output_tokens);
243вҶ’    }
244вҶ’
245вҶ’    saw_usage.then(|| TokenUsage {
246вҶ’        input_tokens: input_tokens.min(u64::from(u32::MAX)) as u32,
247вҶ’        output_tokens: output_tokens.min(u64::from(u32::MAX)) as u32,
248вҶ’    })
249вҶ’}
