251вҶ’fn council_result_to_iteration_result(
252вҶ’    council_result: CouncilPhaseResult,
253вҶ’    phase: &Phase,
254вҶ’) -> IterationResult {
255вҶ’    let token_usage = aggregate_council_token_usage(&council_result);
256вҶ’    let output = council_result.winning_diff;
257вҶ’    let signal_text = council_result
258вҶ’        .worker_results
259вҶ’        .iter()
260вҶ’        .flat_map(|worker| worker.signals.iter().map(String::as_str))
261вҶ’        .collect::<Vec<_>>()
262вҶ’        .join("\n");
263вҶ’    let promise_tag = format!("<promise>{}</promise>", phase.promise);
264вҶ’    let promise_found = output.contains(&promise_tag);
265вҶ’    let signals = extract_signals(&signal_text);
266вҶ’
267вҶ’    IterationResult {
268вҶ’        session: ClaudeSession {
269вҶ’            prompt_file: PathBuf::new(),
270вҶ’            prompt_chars: 0,
271вҶ’            output_file: PathBuf::new(),
272вҶ’            output_chars: output.len(),
273вҶ’            exit_code: 0,
274вҶ’            token_usage,
275вҶ’            session_id: None,
276вҶ’        },
277вҶ’        promise_found,
278вҶ’        output,
279вҶ’        signals,
280вҶ’    }
