 32вҶ’/// Auto-generate spec and phases from an issue description.
 33вҶ’/// Writes a design doc to `.forge/spec.md`, then runs `forge generate`.
 34вҶ’/// Returns Ok(true) if phases were generated successfully, Ok(false) if generation
 35вҶ’/// failed or produced no output (caller should fall back to direct invocation).
 36вҶ’pub(crate) async fn auto_generate_phases(
 37вҶ’    project_path: &str,
 38вҶ’    issue_title: &str,
 39вҶ’    issue_description: &str,
 40вҶ’) -> Result<bool> {
 41вҶ’    // Ensure .forge directory exists
 42вҶ’    let forge_dir = std::path::Path::new(project_path).join(".forge");
 43вҶ’    if !forge_dir.exists() {
 44вҶ’        tokio::fs::create_dir_all(&forge_dir)
 45вҶ’            .await
 46вҶ’            .context("Failed to create .forge directory")?;
 47вҶ’    }
 48вҶ’
 49вҶ’    // Write a design document from the issue
 50вҶ’    let design_content = format!(
 51вҶ’        "# {}\n\n## Overview\n\n{}\n\n## Requirements\n\n- Implement the feature described above\n- Ensure all existing tests continue to pass\n- Add tests for new functionality\n",
 52вҶ’        issue_title,
 53вҶ’        if issue_description.is_empty() {
 54вҶ’            "No additional details provided."
 55вҶ’        } else {
 56вҶ’            issue_description
 57вҶ’        }
 58вҶ’    );
 59вҶ’    let design_path = forge_dir.join("spec.md");
 60вҶ’    tokio::fs::write(&design_path, &design_content)
 61вҶ’        .await
 62вҶ’        .context("Failed to write design document")?;
 63вҶ’
 64вҶ’    // Run forge generate to create phases.json
 65вҶ’    let forge_cmd = std::env::var("FORGE_CMD").unwrap_or_else(|_| "forge".to_string());
 66вҶ’    let status = match tokio::process::Command::new(&forge_cmd)
 67вҶ’        .arg("generate")
 68вҶ’        .current_dir(project_path)
 69вҶ’        .stdout(Stdio::piped())
 70вҶ’        .stderr(Stdio::piped())
 71вҶ’        .status()
 72вҶ’        .await
 73вҶ’    {
 74вҶ’        Ok(s) => s,
 75вҶ’        Err(e) => {
 76вҶ’            warn!("Failed to spawn '{}': {e}", forge_cmd);
 77вҶ’            return Ok(false);
 78вҶ’        }
 79вҶ’    };
 80вҶ’
 81вҶ’    if status.success() && has_forge_phases(project_path) {
 82вҶ’        Ok(true)
 83вҶ’    } else {
 84вҶ’        // Generation failed вҖ” fall back to simple Claude invocation
 85вҶ’        Ok(false)
 86вҶ’    }
 87вҶ’}
