 89вҶ’/// Build the command to execute: `forge swarm` if phases exist, otherwise `claude --print`.
 90вҶ’pub(crate) fn build_execution_command(
 91вҶ’    project_path: &str,
 92вҶ’    issue_title: &str,
 93вҶ’    issue_description: &str,
 94вҶ’) -> tokio::process::Command {
 95вҶ’    if has_forge_phases(project_path) {
 96вҶ’        // Use forge swarm for full DAG-based parallel execution
 97вҶ’        let forge_cmd = std::env::var("FORGE_CMD").unwrap_or_else(|_| "forge".to_string());
 98вҶ’        let mut cmd = tokio::process::Command::new(&forge_cmd);
 99вҶ’        cmd.arg("swarm")
100вҶ’            .arg("--max-parallel")
101вҶ’            .arg("4")
102вҶ’            .arg("--fail-fast")
103вҶ’            .env_remove("CLAUDECODE")
104вҶ’            .current_dir(project_path)
105вҶ’            .stdout(Stdio::piped())
106вҶ’            .stderr(Stdio::piped());
107вҶ’        cmd
108вҶ’    } else {
109вҶ’        // Fallback: direct Claude invocation for simple issues without phases
110вҶ’        // Uses stream-json output format for realtime output streaming to the UI
111вҶ’        let claude_cmd = std::env::var("CLAUDE_CMD").unwrap_or_else(|_| "claude".to_string());
112вҶ’        let prompt = format!(
113вҶ’            "Implement the following issue:\n\nTitle: {}\n\nDescription: {}\n",
114вҶ’            issue_title, issue_description
115вҶ’        );
116вҶ’        let mut cmd = tokio::process::Command::new(&claude_cmd);
117вҶ’        cmd.arg("--print")
118вҶ’            .arg("--verbose")
119вҶ’            .arg("--output-format")
120вҶ’            .arg("stream-json")
121вҶ’            .arg("--dangerously-skip-permissions")
122вҶ’            .arg(&prompt)
123вҶ’            .env_remove("CLAUDECODE")
124вҶ’            .current_dir(project_path)
125вҶ’            .stdout(Stdio::piped())
126вҶ’            .stderr(Stdio::piped());
127вҶ’        cmd
128вҶ’    }
129вҶ’}
