 27вҶ’/// Async database handle wrapping a libsql Database.
 28вҶ’///
 29вҶ’/// Supports three modes:
 30вҶ’/// - **Local SQLite** (dev/offline fallback)
 31вҶ’/// - **Turso embedded replica** with local cache and sync
 32вҶ’/// - **Turso remote HTTP** (pure HTTP, no local cache вҖ” fallback when replica handshake fails)
 33вҶ’#[derive(Clone)]
 34вҶ’pub struct DbHandle {
 35вҶ’    db: Arc<Database>,
