 299вҶ’// Snapshot of a run's current state.
 300вҶ’message RunInfo {
 301вҶ’  string id = 1;
 302вҶ’  string project = 2;
 303вҶ’  RunStatus status = 3;
 304вҶ’
 305вҶ’  // Top-level milestones (phases) in execution order.
 306вҶ’  repeated Milestone milestones = 4;
 307вҶ’
 308вҶ’  // Total number of task nodes (including children) in this run.
 309вҶ’  int32 task_count = 5;
 310вҶ’
 311вҶ’  // Cumulative token usage across all tasks in this run.
 312вҶ’  TokenUsage token_usage = 6;
 313вҶ’
 314вҶ’  // Estimated cost in USD.
 315вҶ’  double estimated_cost_usd = 7;
 316вҶ’
 317вҶ’  // Runtime backend in use for this run.
 318вҶ’  RuntimeBackend runtime_backend = 8;
 319вҶ’
 320вҶ’  // Whether the run is executing in insecure host mode.
 321вҶ’  bool insecure_host_runtime = 9;
 322вҶ’
 323вҶ’  google.protobuf.Timestamp submitted_at = 10;
 324вҶ’  google.protobuf.Timestamp started_at = 11;
 325вҶ’  google.protobuf.Timestamp finished_at = 12;
 326вҶ’
 327вҶ’  // Human-readable failure reason when status is FAILED or CANCELLED.
 328вҶ’  string failure_reason = 13;
 329вҶ’
 330вҶ’  // Canonical submitted plan persisted by the daemon.
 331вҶ’  RunPlan submitted_plan = 14;
