  1вҶ’//! Strongly-typed identifier newtypes for the Forge runtime domain.
  2вҶ’//!
  3вҶ’//! Each ID wraps a `String` and provides `Display`, `From<String>`, `AsRef<str>`,
  4вҶ’//! and serde support. Using newtype wrappers prevents accidental misuse of one
  5вҶ’//! identifier kind where another is expected (e.g., passing a `RunId` where an
  6вҶ’//! `AgentId` is required).
  7вҶ’
  8вҶ’use serde::{Deserialize, Serialize};
  9вҶ’use std::fmt;
 10вҶ’
 11вҶ’macro_rules! define_id {
 12вҶ’    ($(#[doc = $doc:expr])* $name:ident) => {
 13вҶ’        $(#[doc = $doc])*
 14вҶ’        #[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
 15вҶ’        pub struct $name(String);
 16вҶ’
 17вҶ’        impl $name {
 18вҶ’            /// Create a new identifier from any string-like value.
 19вҶ’            pub fn new(id: impl Into<String>) -> Self {
 20вҶ’                Self(id.into())
 21вҶ’            }
 22вҶ’
 23вҶ’            /// Generate a new random identifier using a UUID v4.
 24вҶ’            pub fn generate() -> Self {
 25вҶ’                Self(uuid::Uuid::new_v4().to_string())
 26вҶ’            }
 27вҶ’
 28вҶ’            /// Return the inner string slice.
 29вҶ’            pub fn as_str(&self) -> &str {
 30вҶ’                &self.0
 31вҶ’            }
 32вҶ’
 33вҶ’            /// Consume the wrapper and return the inner `String`.
 34вҶ’            pub fn into_inner(self) -> String {
 35вҶ’                self.0
 36вҶ’            }
 37вҶ’        }
