// Copyright 2026 Forge Contributors
// SPDX-License-Identifier: Apache-2.0
//
// Forge Runtime Platform вҖ” gRPC contract between forge CLI / Factory clients
// and the forge-runtime daemon. Communicates over a Unix domain socket at
// $FORGE_RUNTIME_DIR/forge.sock.
//
// Design reference: docs/superpowers/specs/2026-03-13-forge-runtime-platform-design.md

syntax = "proto3";

package forge.runtime.v1;

import "google/protobuf/timestamp.proto";
import "google/protobuf/duration.proto";
import "google/protobuf/struct.proto";

option java_multiple_files = true;
option java_package = "com.forge.runtime.v1";
option go_package = "forge/runtime/v1;runtimev1";

// ---------------------------------------------------------------------------
// Service
// ---------------------------------------------------------------------------

// ForgeRuntime is the primary API exposed by the forge-runtime daemon.
// CLI, Factory, and agent processes connect over a Unix domain socket.
service ForgeRuntime {
  // ---- Run lifecycle -------------------------------------------------------

  // Submit a new run for execution. The daemon validates policy, persists the
  // run, and begins scheduling. Returns the initial RunInfo snapshot.
  rpc SubmitRun(SubmitRunRequest) returns (RunInfo);

  // Attach to a running (or completed) run and receive a replay of events
  // after `after_cursor`, followed by a live tail. Supports
  // CLI disconnect/reconnect without state loss.
  rpc AttachRun(AttachRunRequest) returns (stream RuntimeEvent);

  // Request graceful stop of a run. In-flight tasks receive SIGTERM; the
  // daemon waits a grace period before force-killing.
  rpc StopRun(StopRunRequest) returns (RunInfo);

  // Fetch the current snapshot of a run.
  rpc GetRun(GetRunRequest) returns (RunInfo);

  // List runs, optionally filtered by project or status.
  rpc ListRuns(ListRunsRequest) returns (ListRunsResponse);

  // ---- Task lifecycle ------------------------------------------------------

  // Fetch a single task node.
  rpc GetTask(GetTaskRequest) returns (TaskInfo);

  // List task nodes within a run.
  rpc ListTasks(ListTasksRequest) returns (ListTasksResponse);

  // Stream a task-scoped filtered projection of output chunks from the
  // authoritative runtime event log.
  rpc StreamTaskOutput(StreamTaskOutputRequest) returns (stream TaskOutputEvent);

  // Create a child task node under an existing parent. The daemon runs the
  // request through the policy engine and may gate on approval.
  rpc CreateChildTask(CreateChildTaskRequest) returns (CreateChildTaskResponse);

  // Terminate a task. The daemon sends SIGTERM to the agent, waits a grace
  // period, then SIGKILL.
  rpc KillTask(KillTaskRequest) returns (KillTaskResponse);

  // ---- Approval flow -------------------------------------------------------

  // Stream pending approval requests. The daemon pushes new requests as they
  // arise; the client resolves them via ResolveApproval.
  rpc PendingApprovals(PendingApprovalsRequest) returns (stream ApprovalRequest);

  // Approve or deny a pending approval request.
  rpc ResolveApproval(ResolveApprovalRequest) returns (ResolveApprovalResponse);

  // ---- MCP service management ----------------------------------------------

