 140вҶ’  RUNTIME_BACKEND_BWRAP       = 1; // Linux bubblewrap namespaces
 141вҶ’  RUNTIME_BACKEND_DOCKER      = 2; // Docker container (macOS primary, Linux optional)
 142вҶ’  RUNTIME_BACKEND_HOST        = 3; // Explicit insecure host mode вҖ” no isolation
 143вҶ’}
 144вҶ’
 145вҶ’// Action taken on an approval request.
 146вҶ’enum ApprovalAction {
 147вҶ’  APPROVAL_ACTION_UNSPECIFIED = 0;
 148вҶ’  APPROVAL_ACTION_APPROVE     = 1;
 149вҶ’  APPROVAL_ACTION_DENY        = 2;
 150вҶ’}
 151вҶ’
 152вҶ’// Who is permitted to resolve an approval request.
 153вҶ’enum ApprovalActorKind {
 154вҶ’  APPROVAL_ACTOR_KIND_UNSPECIFIED = 0;
 155вҶ’  APPROVAL_ACTOR_KIND_PARENT_TASK = 1;
 156вҶ’  APPROVAL_ACTOR_KIND_OPERATOR    = 2;
 157вҶ’  APPROVAL_ACTOR_KIND_AUTO        = 3;
 158вҶ’}
 159вҶ’
 160вҶ’// Why an approval gate was triggered.
 161вҶ’enum ApprovalReasonKind {
 162вҶ’  APPROVAL_REASON_KIND_UNSPECIFIED            = 0;
 163вҶ’  APPROVAL_REASON_KIND_SOFT_CAP_EXCEEDED      = 1;
 164вҶ’  APPROVAL_REASON_KIND_CAPABILITY_ESCALATION  = 2;
 165вҶ’  APPROVAL_REASON_KIND_BUDGET_EXCEPTION       = 3;
 166вҶ’  APPROVAL_REASON_KIND_PROFILE_APPROVAL       = 4;
 167вҶ’  APPROVAL_REASON_KIND_MEMORY_PROMOTION       = 5;
 168вҶ’  APPROVAL_REASON_KIND_INSECURE_RUNTIME_RESTRICTION = 6;
 169вҶ’}
 170вҶ’
 171вҶ’// Current approval state of a task node.
 172вҶ’enum ApprovalState {
 173вҶ’  APPROVAL_STATE_UNSPECIFIED  = 0;
 174вҶ’  APPROVAL_STATE_NOT_REQUIRED = 1;
 175вҶ’  APPROVAL_STATE_PENDING      = 2;
 176вҶ’  APPROVAL_STATE_APPROVED     = 3;
 177вҶ’  APPROVAL_STATE_DENIED       = 4;
 178вҶ’}
 179вҶ’
 180вҶ’// Approval posture for child creation within a milestone or task envelope.
 181вҶ’enum ApprovalMode {
 182вҶ’  APPROVAL_MODE_UNSPECIFIED           = 0;
 183вҶ’  APPROVAL_MODE_AUTO_WITHIN_ENVELOPE  = 1;
 184вҶ’  APPROVAL_MODE_PARENT_WITHIN_ENVELOPE = 2;
 185вҶ’  APPROVAL_MODE_OPERATOR_REQUIRED     = 3;
 186вҶ’}
 187вҶ’
 188вҶ’// Memory scope for task data.
 189вҶ’enum MemoryScope {
 190вҶ’  MEMORY_SCOPE_UNSPECIFIED = 0;
 191вҶ’  MEMORY_SCOPE_SCRATCH     = 1; // Agent-local, lifetime = agent
 192вҶ’  MEMORY_SCOPE_RUN_SHARED  = 2; // Lane-scoped append-only by default, lifetime = run
 193вҶ’  MEMORY_SCOPE_PROJECT     = 3; // Cross-run durable, deny-by-default writes
 194вҶ’}
 195вҶ’
 196вҶ’// Default run-shared write model.
 197вҶ’enum RunSharedWriteMode {
 198вҶ’  RUN_SHARED_WRITE_MODE_UNSPECIFIED = 0;
 199вҶ’  RUN_SHARED_WRITE_MODE_APPEND_ONLY_LANE = 1;
 200вҶ’  RUN_SHARED_WRITE_MODE_COORDINATED_SHARED_WRITE = 2;
 201вҶ’}
 202вҶ’
 203вҶ’// Repository filesystem access level.
 204вҶ’enum RepoAccess {
 205вҶ’  REPO_ACCESS_UNSPECIFIED = 0;
 206вҶ’  REPO_ACCESS_NONE        = 1;
 207вҶ’  REPO_ACCESS_READ_ONLY   = 2;
 208вҶ’  REPO_ACCESS_READ_WRITE  = 3;
 209вҶ’}
 210вҶ’
 211вҶ’// Whether a credential is proxy-only or may be exported with explicit approval.
 212вҶ’enum CredentialAccessMode {
 213вҶ’  CREDENTIAL_ACCESS_MODE_UNSPECIFIED = 0;
 214вҶ’  CREDENTIAL_ACCESS_MODE_PROXY_ONLY  = 1;
 215вҶ’  CREDENTIAL_ACCESS_MODE_EXPORTABLE  = 2;
 216вҶ’}
 217вҶ’
 218вҶ’// Whether a parent waits for the child task to complete.
 219вҶ’enum TaskWaitMode {
 220вҶ’  TASK_WAIT_MODE_UNSPECIFIED         = 0;
 221вҶ’  TASK_WAIT_MODE_ASYNC               = 1;
 222вҶ’  TASK_WAIT_MODE_WAIT_FOR_COMPLETION = 2;
 223вҶ’}
 224вҶ’
 225вҶ’// Execution state of an operator-facing milestone.
 226вҶ’enum MilestoneStatus {
 227вҶ’  MILESTONE_STATUS_UNSPECIFIED = 0;
 228вҶ’  MILESTONE_STATUS_PENDING     = 1;
 229вҶ’  MILESTONE_STATUS_RUNNING     = 2;
 230вҶ’  MILESTONE_STATUS_BLOCKED     = 3;
 231вҶ’  MILESTONE_STATUS_COMPLETED   = 4;
 232вҶ’  MILESTONE_STATUS_FAILED      = 5;
 233вҶ’}
 234вҶ’
 235вҶ’// ---------------------------------------------------------------------------
 236вҶ’// Run lifecycle messages
 237вҶ’// ---------------------------------------------------------------------------
 238вҶ’
 239вҶ’message SubmitRunRequest {
 240вҶ’  // Project identifier (e.g. repository path or name).
 241вҶ’  string project = 1;
 242вҶ’
 243вҶ’  // Canonical run plan submitted by the client.
 244вҶ’  RunPlan plan = 2;
 245вҶ’
 246вҶ’  // Absolute path to the workspace root on the host.
 247вҶ’  string workspace = 3;
 248вҶ’
 249вҶ’  // Optional policy overrides supplied by the operator at submission time.
 250вҶ’  // These are merged on top of project and global policy and may only
 251вҶ’  // tighten constraints, never relax them beyond global policy.
 252вҶ’  PolicyOverrides policy_overrides = 4;
 253вҶ’
 254вҶ’  // Optional runtime backend preference. If unspecified the daemon
 255вҶ’  // auto-detects per Section 4.6.
 256вҶ’  RuntimeBackend runtime_backend = 5;
 257вҶ’
 258вҶ’  // Client-supplied idempotency key. If the daemon has already accepted a
 259вҶ’  // run with this key, it returns the existing RunInfo.
 260вҶ’  string idempotency_key = 6;
 261вҶ’
 262вҶ’  // Client authentication context вҖ” daemon may use this for audit and ACL.
 263вҶ’  ClientIdentity client_identity = 7;
 264вҶ’}
 265вҶ’
 266вҶ’// Policy overrides supplied at run submission time.
 267вҶ’message PolicyOverrides {
 268вҶ’  // Maximum total tasks across the entire run.
 269вҶ’  optional int32 max_tasks_total = 1;
 270вҶ’
 271вҶ’  // Maximum children any single task may spawn.
 272вҶ’  optional int32 max_children_per_task = 2;
 273вҶ’
 274вҶ’  // Maximum task tree depth.
 275вҶ’  optional int32 max_depth = 3;
 276вҶ’
 277вҶ’  // Maximum concurrently running agents.
 278вҶ’  optional int32 max_concurrent = 4;
 279вҶ’
 280вҶ’  // Hard cap on total tokens for the run.
 281вҶ’  optional int64 max_tokens_per_run = 5;
 282вҶ’
 283вҶ’  // Hard cap on tokens per individual task.
 284вҶ’  optional int64 max_tokens_per_task = 6;
 285вҶ’
 286вҶ’  // Percentage of budget at which to warn the parent.
 287вҶ’  optional int32 warn_at_percent = 7;
 288вҶ’
 289вҶ’  // Whether submission should require a secure runtime and refuse insecure host mode.
 290вҶ’  optional bool require_secure_runtime = 8;
 291вҶ’
 292вҶ’  // Additional network denials to tighten the effective policy.
 293вҶ’  repeated string network_denylist = 9;
 294вҶ’
 295вҶ’  // Additional credential denials to tighten the effective policy.
 296вҶ’  repeated string credential_denylist = 10;
 297вҶ’}
 298вҶ’
 299вҶ’// Snapshot of a run's current state.
 300вҶ’message RunInfo {
 301вҶ’  string id = 1;
 302вҶ’  string project = 2;
 303вҶ’  RunStatus status = 3;
 304вҶ’
 305вҶ’  // Top-level milestones (phases) in execution order.
 306вҶ’  repeated Milestone milestones = 4;
 307вҶ’
 308вҶ’  // Total number of task nodes (including children) in this run.
 309вҶ’  int32 task_count = 5;
 310вҶ’
 311вҶ’  // Cumulative token usage across all tasks in this run.
 312вҶ’  TokenUsage token_usage = 6;
 313вҶ’
 314вҶ’  // Estimated cost in USD.
 315вҶ’  double estimated_cost_usd = 7;
 316вҶ’
 317вҶ’  // Runtime backend in use for this run.
 318вҶ’  RuntimeBackend runtime_backend = 8;
 319вҶ’
 320вҶ’  // Whether the run is executing in insecure host mode.
 321вҶ’  bool insecure_host_runtime = 9;
 322вҶ’
 323вҶ’  google.protobuf.Timestamp submitted_at = 10;
 324вҶ’  google.protobuf.Timestamp started_at = 11;
 325вҶ’  google.protobuf.Timestamp finished_at = 12;
 326вҶ’
 327вҶ’  // Human-readable failure reason when status is FAILED or CANCELLED.
 328вҶ’  string failure_reason = 13;
 329вҶ’
 330вҶ’  // Canonical submitted plan persisted by the daemon.
 331вҶ’  RunPlan submitted_plan = 14;
 332вҶ’}
 333вҶ’
 334вҶ’// Canonical run plan owned by the daemon.
 335вҶ’message RunPlan {
 336вҶ’  uint32 version = 1;
 337вҶ’  repeated MilestonePlan milestones = 2;
 338вҶ’  repeated TaskTemplate initial_tasks = 3;
 339вҶ’  BudgetEnvelope global_budget = 4;
 340вҶ’}
 341вҶ’
 342вҶ’// A top-level phase / milestone in the submitted run plan.
 343вҶ’message MilestonePlan {
 344вҶ’  string id = 1;
 345вҶ’  string title = 2;
 346вҶ’  string objective = 3;
 347вҶ’  string expected_output = 4;
 348вҶ’  repeated string depends_on = 5;
 349вҶ’  repeated string success_criteria = 6;
 350вҶ’  string default_profile = 7;
 351вҶ’  BudgetEnvelope budget = 8;
 352вҶ’  ApprovalMode approval_mode = 9;
 353вҶ’}
 354вҶ’
 355вҶ’// Root task seeded when a run is first submitted.
 356вҶ’message TaskTemplate {
 357вҶ’  string milestone_id = 1;
 358вҶ’  string objective = 2;
 359вҶ’  string expected_output = 3;
 360вҶ’  string profile_hint = 4;
 361вҶ’  BudgetEnvelope budget = 5;
 362вҶ’  MemoryScope memory_scope = 6;
 363вҶ’  repeated string depends_on_task_ids = 7;
 364вҶ’}
 365вҶ’
 366вҶ’// A top-level phase / milestone snapshot within a running run.
 367вҶ’message Milestone {
 368вҶ’  string id = 1;
 369вҶ’  string title = 2;
 370вҶ’  int32 order = 3;
 371вҶ’  MilestoneStatus status = 4;
 372вҶ’  // Task nodes that belong to this milestone.
 373вҶ’  repeated string task_ids = 5;
 374вҶ’}
 375вҶ’
 376вҶ’// Cumulative token usage.
 377вҶ’message TokenUsage {
 378вҶ’  int64 input_tokens = 1;
 379вҶ’  int64 output_tokens = 2;
 380вҶ’  int64 cache_read_tokens = 3;
 381вҶ’  int64 cache_write_tokens = 4;
 382вҶ’  int64 total_tokens = 5;
 383вҶ’}
 384вҶ’
 385вҶ’message AttachRunRequest {
 386вҶ’  string run_id = 1;
 387вҶ’
 388вҶ’  // Replay events with cursor > after_cursor, then continue with a live tail.
 389вҶ’  int64 after_cursor = 2;
 390вҶ’
 391вҶ’  // Optional filter: only stream events for these task IDs.
 392вҶ’  repeated string task_id_filter = 3;
 393вҶ’
 394вҶ’  ClientIdentity client_identity = 4;
 395вҶ’}
 396вҶ’
 397вҶ’message StopRunRequest {
 398вҶ’  string run_id = 1;
 399вҶ’
 400вҶ’  // Grace period before force-killing agents. If unset, daemon uses its
 401вҶ’  // configured default (typically 30s).
 402вҶ’  google.protobuf.Duration grace_period = 2;
 403вҶ’
 404вҶ’  // Reason for stopping (recorded in audit trail).
 405вҶ’  string reason = 3;
 406вҶ’
 407вҶ’  ClientIdentity client_identity = 4;
 408вҶ’}
 409вҶ’
 410вҶ’message GetRunRequest {
 411вҶ’  string run_id = 1;
 412вҶ’}
 413вҶ’
 414вҶ’message ListRunsRequest {
 415вҶ’  // Filter by project. Empty means all projects.
 416вҶ’  string project = 1;
 417вҶ’
 418вҶ’  // Filter by status. Empty means all statuses.
 419вҶ’  repeated RunStatus status_filter = 2;
 420вҶ’
 421вҶ’  // Pagination.
 422вҶ’  int32 page_size = 3;
 423вҶ’  string page_token = 4;
 424вҶ’}
 425вҶ’
 426вҶ’message ListRunsResponse {
 427вҶ’  repeated RunInfo runs = 1;
 428вҶ’  string next_page_token = 2;
 429вҶ’}
 430вҶ’
 431вҶ’// ---------------------------------------------------------------------------
 432вҶ’// Task lifecycle messages
 433вҶ’// ---------------------------------------------------------------------------
 434вҶ’
 435вҶ’message GetTaskRequest {
 436вҶ’  string task_id = 1;
 437вҶ’}
 438вҶ’
 439вҶ’// Snapshot of a task node within the run graph.
 440вҶ’message TaskInfo {
 441вҶ’  string id = 1;
 442вҶ’  string run_id = 2;
 443вҶ’
 444вҶ’  // Parent task node ID. Empty for root / top-level tasks.
 445вҶ’  string parent_task_id = 3;
 446вҶ’
 447вҶ’  // Milestone this task belongs to (if any).
 448вҶ’  string milestone_id = 4;
 449вҶ’
 450вҶ’  // What the task should accomplish.
 451вҶ’  string objective = 5;
 452вҶ’
 453вҶ’  // What the task is expected to produce.
 454вҶ’  string expected_output = 6;
 455вҶ’
 456вҶ’  // Compiled profile name (e.g. "implementer", "security-reviewer").
 457вҶ’  string profile = 7;
 458вҶ’
 459вҶ’  // Token / resource budget for this task.
 460вҶ’  BudgetEnvelope budget = 8;
 461вҶ’
 462вҶ’  // Memory scope governing scratch, run-shared, or project access.
 463вҶ’  MemoryScope memory_scope = 9;
 464вҶ’
 465вҶ’  TaskStatus status = 10;
 466вҶ’
 467вҶ’  // Agent instance currently assigned to this task (if running).
 468вҶ’  string assigned_agent_id = 11;
 469вҶ’
 470вҶ’  // IDs of direct child task nodes.
 471вҶ’  repeated string children = 12;
 472вҶ’
 473вҶ’  // Resource snapshot of the assigned agent (if running).
 474вҶ’  ResourceSnapshot resource_snapshot = 13;
 475вҶ’
 476вҶ’  // Human-readable failure or kill reason.
 477вҶ’  string failure_reason = 14;
 478вҶ’
 479вҶ’  google.protobuf.Timestamp created_at = 15;
 480вҶ’  google.protobuf.Timestamp started_at = 16;
 481вҶ’  google.protobuf.Timestamp finished_at = 17;
 482вҶ’
 483вҶ’  // Token usage for this task (excluding children).
 484вҶ’  TokenUsage token_usage = 18;
 485вҶ’
 486вҶ’  // Cumulative token usage for this task's entire subtree.
 487вҶ’  TokenUsage subtree_token_usage = 19;
 488вҶ’
 489вҶ’  // Explicit dependency edges in the run graph.
 490вҶ’  repeated string depends_on_task_ids = 20;
 491вҶ’
 492вҶ’  // Current approval state for this task.
 493вҶ’  ApprovalState approval_state = 21;
 494вҶ’
 495вҶ’  // Approved capability envelope for this task subtree.
 496вҶ’  CapabilityEnvelope requested_capabilities = 22;
 497вҶ’
 498вҶ’  // Whether the parent waited for this task to complete.
 499вҶ’  TaskWaitMode wait_mode = 23;
 500вҶ’
 501вҶ’  // Persisted summary of the task result.
 502вҶ’  TaskResultSummary result_summary = 24;
 503вҶ’}
 504вҶ’
 505вҶ’// Budget envelope constraining a task's resource consumption.
 506вҶ’message BudgetEnvelope {
 507вҶ’  // Maximum tokens this task may consume.
 508вҶ’  int64 max_tokens = 1;
 509вҶ’
 510вҶ’  // Maximum wall-clock duration for this task.
 511вҶ’  google.protobuf.Duration max_duration = 2;
 512вҶ’
 513вҶ’  // Maximum number of child tasks this task may create.
 514вҶ’  int32 max_children = 3;
 515вҶ’
 516вҶ’  // Number of children after which approval is required.
 517вҶ’  int32 require_approval_after = 4;
 518вҶ’
 519вҶ’  // Maximum task tree depth below this node.
 520вҶ’  int32 max_depth = 5;
 521вҶ’}
 522вҶ’
 523вҶ’// Point-in-time resource consumption of an agent.
 524вҶ’message ResourceSnapshot {
 525вҶ’  string agent_id = 1;
 526вҶ’  string task_id = 2;
 527вҶ’
 528вҶ’  // CPU usage as a fraction (0.0 вҖ“ N cores).
 529вҶ’  double cpu_usage = 3;
 530вҶ’
 531вҶ’  // Resident memory in bytes.
 532вҶ’  int64 memory_bytes = 4;
 533вҶ’
 534вҶ’  // Disk usage in bytes (task worktree).
 535вҶ’  int64 disk_bytes = 5;
 536вҶ’
 537вҶ’  // Network egress bytes since agent start.
 538вҶ’  int64 network_egress_bytes = 6;
 539вҶ’
 540вҶ’  // Network ingress bytes since agent start.
 541вҶ’  int64 network_ingress_bytes = 7;
 542вҶ’
 543вҶ’  google.protobuf.Timestamp sampled_at = 8;
 544вҶ’}
 545вҶ’
 546вҶ’message ListTasksRequest {
 547вҶ’  string run_id = 1;
 548вҶ’
 549вҶ’  // Optional: filter to tasks under this parent.
 550вҶ’  string parent_task_id = 2;
 551вҶ’
 552вҶ’  // Optional: filter by status.
 553вҶ’  repeated TaskStatus status_filter = 3;
 554вҶ’
 555вҶ’  // Optional: filter by milestone.
 556вҶ’  string milestone_id = 4;
 557вҶ’
 558вҶ’  int32 page_size = 5;
 559вҶ’  string page_token = 6;
 560вҶ’}
 561вҶ’
 562вҶ’message ListTasksResponse {
 563вҶ’  repeated TaskInfo tasks = 1;
 564вҶ’  string next_page_token = 2;
 565вҶ’}
 566вҶ’
 567вҶ’message StreamTaskOutputRequest {
 568вҶ’  string run_id = 1;
 569вҶ’  string task_id = 2;
 570вҶ’
 571вҶ’  // Replay output chunks with cursor > after_cursor.
 572вҶ’  int64 after_cursor = 3;
 573вҶ’
 574вҶ’  ClientIdentity client_identity = 4;
 575вҶ’}
 576вҶ’
 577вҶ’// A single output event projected from the authoritative runtime event log.
 578вҶ’message TaskOutputEvent {
 579вҶ’  string run_id = 1;
 580вҶ’  string task_id = 2;
 581вҶ’  string agent_id = 3;
 582вҶ’
 583вҶ’  // Authoritative runtime-event cursor for this output chunk.
 584вҶ’  int64 cursor = 4;
 585вҶ’
 586вҶ’  google.protobuf.Timestamp timestamp = 5;
 587вҶ’
 588вҶ’  oneof event {
 589вҶ’    // Raw stdout/stderr line from the agent process.
 590вҶ’    StdoutLine stdout_line = 6;
 591вҶ’
 592вҶ’    // Parsed signal tag (<progress>, <blocker>, <pivot>).
 593вҶ’    Signal signal = 7;
 594вҶ’
 595вҶ’    // Promise tag (<promise>DONE</promise>) indicating task completion.
 596вҶ’    Promise promise = 8;
 597вҶ’
 598вҶ’    // Token-usage delta parsed from structured agent output.
 599вҶ’    TokenUsageDelta token_usage = 9;
 600вҶ’  }
 601вҶ’}
 602вҶ’
 603вҶ’message StdoutLine {
 604вҶ’  string line = 1;
 605вҶ’  bool is_stderr = 2;
 606вҶ’}
 607вҶ’
 608вҶ’message Signal {
 609вҶ’  // Signal type: "progress", "blocker", "pivot".
 610вҶ’  string signal_type = 1;
 611вҶ’  string content = 2;
 612вҶ’}
 613вҶ’
 614вҶ’message Promise {
 615вҶ’  string value = 1;
 616вҶ’}
 617вҶ’
 618вҶ’message TokenUsageDelta {
 619вҶ’  int64 tokens = 1;
 620вҶ’  int64 cumulative = 2;
 621вҶ’}
 622вҶ’
 623вҶ’message CreateChildTaskRequest {
 624вҶ’  string run_id = 1;
 625вҶ’  string parent_task_id = 2;
 626вҶ’  string milestone_id = 3;
 627вҶ’
 628вҶ’  // Profile to use for the child agent (e.g. "implementer", "reviewer").
 629вҶ’  string profile = 4;
 630вҶ’
 631вҶ’  // What the child task should accomplish.
 632вҶ’  string objective = 5;
 633вҶ’
 634вҶ’  // What the child task is expected to produce.
 635вҶ’  string expected_output = 6;
 636вҶ’
 637вҶ’  // Budget overrides for the child. If unset, inherits from parent minus
 638вҶ’  // already consumed resources.
 639вҶ’  BudgetEnvelope budget = 7;
 640вҶ’
 641вҶ’  // Memory scope for the child. If unset, defaults to RUN_SHARED.
 642вҶ’  MemoryScope memory_scope = 8;
 643вҶ’
 644вҶ’  // Whether the parent should block until the child completes.
 645вҶ’  TaskWaitMode wait_mode = 9;
 646вҶ’
 647вҶ’  // Explicit dependency edges for the child task.
 648вҶ’  repeated string depends_on_task_ids = 10;
 649вҶ’
 650вҶ’  // Requested capability envelope for the child subtree.
 651вҶ’  CapabilityEnvelope requested_capabilities = 11;
 652вҶ’
 653вҶ’  // Client authentication context for audit.
 654вҶ’  ClientIdentity client_identity = 12;
 655вҶ’}
 656вҶ’
 657вҶ’message CreateChildTaskResponse {
 658вҶ’  // The newly created task node. Status may be PENDING, AWAITING_APPROVAL,
 659вҶ’  // or ENQUEUED depending on policy evaluation.
 660вҶ’  TaskInfo task = 1;
 661вҶ’
 662вҶ’  // True if the child task requires approval before scheduling.
 663вҶ’  bool requires_approval = 2;
 664вҶ’
 665вҶ’  // Approval ID to watch/resolve if requires_approval is true.
 666вҶ’  string approval_id = 3;
 667вҶ’}
 668вҶ’
 669вҶ’message KillTaskRequest {
 670вҶ’  string task_id = 1;
 671вҶ’
 672вҶ’  // Reason for killing (recorded in audit trail and sent to parent).
 673вҶ’  string reason = 2;
 674вҶ’
 675вҶ’  // Grace period before SIGKILL. If unset, daemon default applies.
 676вҶ’  google.protobuf.Duration grace_period = 3;
 677вҶ’
 678вҶ’  ClientIdentity client_identity = 4;
 679вҶ’}
 680вҶ’
 681вҶ’message KillTaskResponse {
 682вҶ’  TaskInfo task = 1;
 683вҶ’}
 684вҶ’
 685вҶ’// ---------------------------------------------------------------------------
 686вҶ’// Approval flow messages
 687вҶ’// ---------------------------------------------------------------------------
 688вҶ’
 689вҶ’message PendingApprovalsRequest {
 690вҶ’  // Optional: scope to a specific run.
 691вҶ’  string run_id = 1;
 692вҶ’
 693вҶ’  ClientIdentity client_identity = 2;
 694вҶ’}
 695вҶ’
 696вҶ’// An approval request generated by the policy engine when a child task
 697вҶ’// creation exceeds soft caps or when the profile requires explicit approval.
 698вҶ’message ApprovalRequest {
 699вҶ’  // Unique approval ID.
 700вҶ’  string id = 1;
 701вҶ’
