 1вҶ’//! Shared domain types for the Forge runtime platform.
 2вҶ’//!
 3вҶ’//! This crate defines the core domain types shared across `forge-cli`,
 4вҶ’//! `forge-runtime`, and `forge-proto`: identifiers, agent manifests,
 5вҶ’//! run-plan / task-graph structures, policy definitions, and runtime events.
 6вҶ’//!
 7вҶ’//! All types are designed for strong typing (newtype IDs, enums with data),
 8вҶ’//! serde support (for persistence and gRPC translation), and clear ownership
 9вҶ’//! semantics aligned with the runtime platform design spec.
10вҶ’
11вҶ’pub mod events;
12вҶ’pub mod ids;
13вҶ’pub mod manifest;
14вҶ’pub mod policy;
15вҶ’pub mod run_graph;
16вҶ’pub mod runtime;
17вҶ’
18вҶ’// Re-export commonly used types at the crate root for convenience.
19вҶ’pub use events::{BusMessage, RuntimeEvent, RuntimeEventKind, TaskOutput, TaskOutputEvent};
20вҶ’pub use ids::{AgentId, ApprovalId, ChannelId, MilestoneId, RunId, SpawnId, TaskNodeId};
21вҶ’pub use manifest::{
22вҶ’    AgentManifest, BudgetEnvelope, CapabilityEnvelope, CompiledProfile, CredentialAccessMode,
23вҶ’    CredentialGrant, MemoryPolicy, MemoryScope, PermissionSet, RepoAccess, ResourceLimits,
24вҶ’    RunSharedWriteMode, RuntimeEnvPlan, SpawnLimits, WorktreePlan,
25вҶ’};
26вҶ’pub use policy::{Policy, PolicyDecision};
27вҶ’pub use run_graph::{
28вҶ’    AgentHandle, AgentInstance, AgentResult, ApprovalActorKind, ApprovalMode,
29вҶ’    ApprovalReasonKind, ApprovalResolution, ApprovalState, MilestoneInfo, MilestoneState,
30вҶ’    MilestoneStatus, PendingApproval, ResourceSnapshot, RunGraph, RunPlan, RunState, RunStatus,
31вҶ’    TaskNode, TaskResultSummary, TaskStatus, TaskTemplate, TaskWaitMode,
32вҶ’};
