//! Bidirectional conversion between proto string fields and forge-common
//! strongly-typed ID newtypes.

use forge_common::{
    AgentId, ApprovalId, ChannelId, MilestoneId, RunId, SpawnId, TaskNodeId,
};

macro_rules! impl_id_convert {
    ($id_type:ty) => {
        impl From<$id_type> for String {
            fn from(id: $id_type) -> Self {
                id.into_inner()
            }
        }

        impl From<String> for $id_type {
            fn from(s: String) -> Self {
                <$id_type>::new(s)
            }
        }
    };
}

impl_id_convert!(RunId);
impl_id_convert!(TaskNodeId);
impl_id_convert!(AgentId);
impl_id_convert!(MilestoneId);
impl_id_convert!(ApprovalId);
impl_id_convert!(SpawnId);
impl_id_convert!(ChannelId);

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn run_id_roundtrip() {
        let id = RunId::new("run-123");
        let s: String = id.clone().into();
        let back: RunId = s.into();
        assert_eq!(id, back);
    }

    #[test]
    fn task_node_id_roundtrip() {
        let id = TaskNodeId::generate();
        let s: String = id.clone().into();
        let back: TaskNodeId = s.into();
        assert_eq!(id, back);
    }
}
```

