            version: p.version,
            milestones: p.milestones.iter().map(MilestoneInfo::from).collect(),
            initial_tasks: p.initial_tasks.iter().map(TaskTemplate::from).collect(),
            global_budget: p
                .global_budget
                .as_ref()
