```rust
//! Conversion between proto manifest messages and forge-common manifest types.

use crate::proto;
use forge_common::{
    manifest::{
        BudgetEnvelope, CapabilityEnvelope, CredentialAccessMode, CredentialGrant, MemoryPolicy,
        MemoryScope, PermissionSet, RepoAccess, ResourceLimits, RunSharedWriteMode, SpawnLimits,
    },
    AgentManifest,
};

// --- BudgetEnvelope ---

impl From<&BudgetEnvelope> for proto::BudgetEnvelope {
    fn from(b: &BudgetEnvelope) -> Self {
        proto::BudgetEnvelope {
            max_tokens: b.allocated,
            max_duration: None, // domain type doesn't track duration yet
            max_children: 0,    // tracked in SpawnLimits, not budget
            require_approval_after: 0,
            max_depth: 0,
        }
