                .ok()
                .and_then(|v| MemoryScope::try_from(v).ok())
                .unwrap_or(MemoryScope::Scratch),
            depends_on: p.depends_on_task_ids.iter().map(|s| TaskNodeId::new(s)).collect(),
        }
    }
